      if (langCode == 'uk') return 'Політика відповідності (закон про торговельні марки та цілісність продукту)';
      if (langCode == 'ur') return 'تعمیل کی پالیسی (ٹریڈ مارک قانون اور مصنوعات کی سالمیت)';
      return 'Compliance-Richtlinie (Markenrecht & Produktintegrität)';
    case 'privacy':
